from azure.servicebus import ServiceBusClient, ServiceBusMessage
from azure.functions import ServiceBusMessage as AzureServiceBusMessage

# Environment variables for Service Bus
CONNECTION_STR = os.getenv('SERVICE_BUS_CONNECTION_STRING')
QUEUE_NAME = os.getenv('SERVICE_BUS_QUEUE_NAME')

def main(msg: AzureServiceBusMessage):
    try:
        # Deserialize the message content securely
        message_content = msg.get_body().decode('utf-8')
        
        # Validate the message content
        if not isinstance(message_content, str) or not message_content:
            logging.error("Invalid message content")
            return
        
        # Deserialize using pickle with caution
        try:
            data = pickle.loads(message_content.encode('utf-8'))
        except (pickle.UnpicklingError, ValueError) as e:
            logging.error(f"Deserialization error: {e}")
            return
        
        # Process the deserialized data
        process_data(data)
        
    except Exception as e:
        logging.error(f"Error processing message: {e}")

def process_data(data):
    # Implement your data processing logic here
    logging.info(f"Processing data: {data}")

def send_message_to_queue(data):
    # Serialize data securely
    try:
        serialized_data = pickle.dumps(data)
    except pickle.PicklingError as e:
        logging.error(f"Serialization error: {e}")
        return
    
    with ServiceBusClient.from_connection_string(CONNECTION_STR) as client:
        with client.get_queue_sender(QUEUE_NAME) as sender:
            message = ServiceBusMessage(serialized_data)
